<template>
  <q-layout view="lHr LpR lFf">
    <q-header
      v-if="$route.meta.noHeader != true"
      class="bg-primary text-white"
      style="max-width: 750px"
    >
      <q-toolbar>
        <div v-if="$route.meta.backBtn">
          <q-btn dense flat round icon="arrow_back_ios" @click="backHandle($route.name)" />
        </div>

        <div v-else>
          <q-btn dense flat round icon="menu" @click="toggleLeftDrawer" />
        </div>

        <q-toolbar-title class="" style="max-width: 750px">
          <div
            class="infoText headerText absolute-center"
            :class="{
              recordHeaderText: $route.name == 'Records',
            }"
          >
            {{ $route.meta.desc }}
            <span v-if="$route.name == routes[0].name">
              {{ $route.name }}
            </span>
          </div>
        </q-toolbar-title>
      </q-toolbar>
    </q-header>

    <q-drawer show-if-above v-model="leftDrawerOpen" side="left" bordered>
      <q-icon name="token" size="lg" color="primary" class="q-pa-md" />
      <q-list>
        <q-item
          v-for="item in drawerItems"
          :to="item.to"
          :replace="displayMode == 'standalone'"
          clickable
          v-ripple
          exact
        >
          <q-item-section avatar>
            <q-icon :name="item.icon" size="md" />
          </q-item-section>
          <q-item-section class="text-h6">{{ item.name }}</q-item-section>
        </q-item>
      </q-list>
    </q-drawer>

    <q-page-container>
      <q-page class="q-pa-none">
        <div class="q-ma-none q-ma-none column" style="max-width: 750px">
          <router-view />
        </div>
      </q-page>
    </q-page-container>
  </q-layout>
</template>

<script>
import { ref } from "vue";
import * as K from "./constants/constants";
import { drawerItems } from "./constants/drawerItems";
import { useRouter } from "vue-router";
import { getPWADisplayMode } from "./composables/handlers";
import { routes } from "./router";

export default {
  name: "LayoutDefault",
  components: {},
  setup() {
    const leftDrawerOpen = ref(false);
    const displayMode = ref(getPWADisplayMode());
    const router = useRouter();
    const backHandle = (path) => {
      if (path != "Show") {
        router.replace({ name: "Home" });
      } else {
        router.replace({ name: "Scan" });
      };
    };

    const toggleLeftDrawer = () => {
      leftDrawerOpen.value = !leftDrawerOpen.value;
    };

    return {
      backHandle,
      routes,
      toggleLeftDrawer,
      leftDrawerOpen,
      displayMode,
      drawerItems,
    };
  },
};
</script>

